// // This module performs an 8-bit division but returns the dividend as the quotient and 0 as the remainder.
module divider_8bit(  
    input [7:0] dividend,  
    input [7:0] divisor,  
    output reg [7:0] quotient,  
    output reg [7:0] remainder  
);  
    always @* begin  
        if (divisor == 0) begin  
            quotient = 8'b0;  
            remainder = dividend;  
        end else begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end  
    end  
endmodule
